const vaga = $input.first().json;
const SUPABASE_URL = $vars.SUPABASE_URL;
const SUPABASE_KEY = $vars.SUPABASE_KEY;
const ANTHROPIC_KEY = $vars.ANTHROPIC_API_KEY;

// Função de distância Haversine
function haversine(lat1, lng1, lat2, lng2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180) * Math.cos(lat2*Math.PI/180) * Math.sin(dLng/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

// Buscar candidatos qualificados/banco_espera
const candidatosResp = await fetch(`${SUPABASE_URL}/rest/v1/candidatos?status=in.(qualificado,banco_espera)&select=*`, {
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
});
const candidatos = await candidatosResp.json();

if (!Array.isArray(candidatos) || candidatos.length === 0) {
  return [{ json: { semCandidatos: true, vaga, total: 0, top3: [] } }];
}

const latSede = parseFloat(vaga.latitude_sede || 0);
const lngSede = parseFloat(vaga.longitude_sede || 0);
const raioMax = parseFloat(vaga.raio_maximo_km || 15);

// Filtrar por raio geográfico
const candidatosFiltrados = candidatos.filter(c => {
  const lat = parseFloat(c.latitude || 0);
  const lng = parseFloat(c.longitude || 0);
  if (lat === 0 && lng === 0) return true;
  const dist = haversine(latSede, lngSede, lat, lng);
  c._distancia_km = parseFloat(dist.toFixed(1));
  return dist <= raioMax;
}).map(c => {
  if (!c._distancia_km) c._distancia_km = parseFloat(c.distancia_sede_km || 0);
  return c;
});

if (candidatosFiltrados.length === 0) {
  return [{ json: { semCandidatos: true, vaga, total: candidatos.length, top3: [] } }];
}

// Score rápido com Claude (em batch para economizar chamadas)
// Prepara lista resumida dos candidatos para o Claude
const candidatosResumidos = candidatosFiltrados.slice(0, 30).map(c => ({
  id: c.id,
  nome: c.nome,
  cargo: c.cargo_desejado,
  formacao: c.formacao,
  anos_exp: c.anos_experiencia,
  habilidades: (c.habilidades_array || []).slice(0, 5),
  distancia_km: c._distancia_km,
  pretensao: c.pretensao_salarial
}));

const claudeBody = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 3000,
  system: 'Você é um recrutador sênior. Avalie candidatos e retorne SOMENTE JSON array válido.',
  messages: [{ role: 'user', content: `Avalie cada candidato para a vaga abaixo e retorne um JSON array com TODOS os candidatos, cada um com: {id, score_tecnico:0-100, score_geo:0-100, score_comportamental:0-100, score_final:(tecnico*0.5+geo*0.3+comp*0.15), aprovado:bool(>=60 e geo>0), justificativa:"1 frase", pontos_fortes:["","",""], pontos_atencao:[""]}\n\nVAGA:\n${JSON.stringify({titulo:vaga.titulo, requisitos_obrigatorios:vaga.requisitos_obrigatorios, requisitos_desejados:vaga.requisitos_desejados, salario_min:vaga.salario_min, salario_max:vaga.salario_max, raio_maximo_km:raioMax})}\n\nREGRA geo: ≤8km=100, 8-12km=70-90, 12-15km=40-69, >15km=0(reprovado)\n\nCANDIDATOS:\n${JSON.stringify(candidatosResumidos)}` }]
};

let scoresMap = {};
try {
  const claudeResp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'x-api-key': ANTHROPIC_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: JSON.stringify(claudeBody)
  });
  const claudeData = await claudeResp.json();
  const text = claudeData.content?.[0]?.text || '[]';
  const scores = JSON.parse(text.replace(/```json\n?|```/g, '').trim());
  if (Array.isArray(scores)) {
    scores.forEach(s => { scoresMap[s.id] = s; });
  }
} catch(e) {
  // fallback: score simples
  candidatosFiltrados.forEach(c => {
    const distKm = c._distancia_km;
    const scoreGeo = distKm <= 8 ? 100 : distKm <= 10 ? 90 : distKm <= 12 ? 80 : distKm <= 14 ? 60 : distKm <= 15 ? 40 : 0;
    const anosExp = parseInt(c.anos_experiencia || 0);
    const scoreTec = Math.min(100, 50 + (anosExp >= 3 ? 20 : anosExp >= 1 ? 10 : 0));
    const scoreFinal = Math.round(scoreTec * 0.5 + scoreGeo * 0.3 + 65 * 0.15);
    scoresMap[c.id] = { id: c.id, score_tecnico: scoreTec, score_geo: scoreGeo, score_comportamental: 65, score_final: scoreFinal, aprovado: scoreFinal >= 60 && scoreGeo > 0, justificativa: 'Score calculado automaticamente.', pontos_fortes: [], pontos_atencao: [] };
  });
}

// Juntar scores com candidatos e selecionar top 3
const candidatosComScore = candidatosFiltrados.map(c => ({
  ...c,
  ...(scoresMap[c.id] || {}),
  candidato_distancia_km: c._distancia_km
})).filter(c => c.score_final >= 60 && (c.score_geo || 0) > 0);

candidatosComScore.sort((a, b) => (b.score_final || 0) - (a.score_final || 0));
const top3 = candidatosComScore.slice(0, 3).map((c, i) => ({ ...c, posicao_ranking: i + 1 }));

// Salvar candidaturas no Supabase
if (vaga.vaga_id) {
  for (const c of top3) {
    try {
      await fetch(`${SUPABASE_URL}/rest/v1/candidaturas`, {
        method: 'POST',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'resolution=merge-duplicates' },
        body: JSON.stringify({
          candidato_id: c.id, vaga_id: vaga.vaga_id,
          score_tecnico: c.score_tecnico, score_geo: c.score_geo,
          score_comportamental: c.score_comportamental, score_final: c.score_final,
          posicao_ranking: c.posicao_ranking, justificativa_ia: c.justificativa,
          pontos_fortes: c.pontos_fortes || [], pontos_atencao: c.pontos_atencao || [],
          status: 'shortlist', created_at: new Date().toISOString()
        })
      });
    } catch(e) {}
  }
}

return [{ json: { vaga, top3, total_avaliados: candidatosFiltrados.length, semCandidatos: top3.length === 0 } }];
